code = """import json

# Read data from files
with open('var_functions.query_db:52', 'r') as f:
    businesses = json.load(f)

with open('var_functions.query_db:53', 'r') as f:
    ratings = json.load(f)

# Create rating lookup dictionary
rating_dict = {}
for r in ratings:
    rating_dict[r['gmap_id']] = float(r['avg_rating'])

# Define weekdays
weekdays = {'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday'}

def is_open_after_6pm(hours_str):
    if not hours_str or hours_str == 'None':
        return False
    
    s = hours_str.lower()
    
    # Check for 24 hour businesses
    if 'open 24 hours' in s:
        return True
    
    # Check for evening hours on weekdays
    for day in weekdays:
        if day.lower() in s:
            # Look for PM times after 6PM or AM times (late night)
            evening_times = ['7pm', '8pm', '9pm', '10pm', '11pm', '12am', '1am', '2am', '3am', '4am', '5am', '6am']
            if any(time in s for time in evening_times):
                return True
    
    return False

# Find eligible businesses with ratings
eligible = []
for biz in businesses:
    if is_open_after_6pm(biz['hours']):
        gmap_id = biz['gmap_id']
        if gmap_id in rating_dict:
            eligible.append({
                'name': biz['name'],
                'avg_rating': rating_dict[gmap_id],
                'hours': biz['hours']
            })

# Sort by rating descending
eligible.sort(key=lambda x: x['avg_rating'], reverse=True)

# Get top 5 and round ratings
result = []
for biz in eligible[:5]:
    result.append({
        'name': biz['name'],
        'avg_rating': round(biz['avg_rating'], 2),
        'hours': biz['hours']
    })

# Print in required format
output = json.dumps(result, indent=2)
print('__RESULT__:')
print(output)"""

